INSERT INTO departments (department_id, department_name, description) VALUES
    (1, 'Administration', 'Handles office administration, facilities and general operations.'),
    (2, 'AI & Machine Learning', 'Builds and maintains machine learning models and AI-driven features.'),
    (3, 'Business Analytics', 'Analyzes business data to support decision making and reporting.'),
    (4, 'DevOps', 'Manages CI/CD pipelines, infrastructure and deployment automation.'),
    (5, 'Finance', 'Manages budgeting, payroll, invoicing and financial reporting.'),
    (6, 'Human Resources', 'Manages recruitment, onboarding, and employee relations.'),
    (7, 'Information Technology', 'Core software engineering and IT infrastructure team.'),
    (8, 'Quality Assurance', 'Responsible for manual and automated testing of all products.'),
    (9, 'Sales & Marketing', 'Drives lead generation, client outreach and marketing campaigns.'),
    (10, 'UI/UX Design', 'Designs user interfaces and user experience across all products.');
